class Solution {
public:
    string mergeAlternately(string word1, string word2) {
        string word;
        int biggest;
        if (word1.length() <= word2.length())
            biggest = word2.length();
        else 
            biggest = word1.length();
        for (int i = 0; i < biggest; i++) {
            if (word1.length() > i)
                word += word1[i];
            if (word2.length() > i)
                word += word2[i];
        }
        return word;
    }
};

